def fib_memo(n):
    memo = {0: 0, 1: 1}

    if n < 0:
        raise ValueError("n must be a non-negative integer")

    for num in range(2, n + 1):
        a, b = memo[num - 1], memo[num - 2]
        memo[num] = a + b

    return memo[n]
