{"code":"def fib_memo(n):
    """Return the n-th Fibonacci number (0-indexed) using memoization.
    Raises ValueError for negative inputs.
    """
    if n < 0:
        raise ValueError("n must be non‑negative")
    memo = {0: 0, 1: 1}
    def helper(k):
        if k in memo:
            return memo[k]
        memo[k] = helper(k - 1) + helper(k - 2)
        return memo[k]
    return helper(n)"}

{
  "code": "def fib_memo(n):
    """Return the nth Fibonacci number (0-indexed) using memoization.

    The function creates an internal dictionary to store previously
    computed values, ensuring O(n) time for n up to 100 (or much larger).
    No global variables or functools.lru_cache are used.
    """
    memo = {0: 0, 1: 1}
    def helper(k):
        if k in memo:
            return memo[k]
        memo[k] = helper(k - 1) + helper(k - 2)
        return memo[k]
    return helper(n)"
}
